const exercise = $input.first().json;

const statements = [];

// 1. Opret Øvelse-node
statements.push({
  statement: `MERGE (e:Øvelse {id: $id}) 
    SET e.navn = $name, e.force = $force, 
    e.level = $level, e.mechanic = $mechanic`,
  parameters: {
    id: exercise.id,
    name: exercise.name,
    force: exercise.force,
    level: exercise.level,
    mechanic: exercise.mechanic
  }
});

// 2. Opret Niveau-node + relation
statements.push({
  statement: `MERGE (n:Niveau {navn: $level})
    WITH n
    MATCH (e:Øvelse {id: $id})
    MERGE (e)-[:HAR_NIVEAU]->(n)`,
  parameters: { level: exercise.level, id: exercise.id }
});

// 3. Opret Udstyr-node + relation
statements.push({
  statement: `MERGE (u:Udstyr {type: $equipment})
    WITH u
    MATCH (e:Øvelse {id: $id})
    MERGE (e)-[:KRÆVER_UDSTYR]->(u)`,
  parameters: { equipment: exercise.equipment, id: exercise.id }
});

// 4. Opret Kategori-node + relation
statements.push({
  statement: `MERGE (k:Kategori {navn: $category})
    WITH k
    MATCH (e:Øvelse {id: $id})
    MERGE (e)-[:I_KATEGORI]->(k)`,
  parameters: { category: exercise.category, id: exercise.id }
});

// 5. Primære muskler + relationer
for (const muscle of exercise.primaryMuscles) {
  statements.push({
    statement: `MERGE (m:Muskelgruppe {navn: $muscle})
      WITH m
      MATCH (e:Øvelse {id: $id})
      MERGE (e)-[:PRIMÆR_MUSKEL]->(m)`,
    parameters: { muscle, id: exercise.id }
  });
}

// 6. Sekundære muskler + relationer
for (const muscle of exercise.secondaryMuscles) {
  statements.push({
    statement: `MERGE (m:Muskelgruppe {navn: $muscle})
      WITH m
      MATCH (e:Øvelse {id: $id})
      MERGE (e)-[:SEKUNDÆR_MUSKEL]->(m)`,
    parameters: { muscle, id: exercise.id }
  });
}

return [{ json: { statements } }];

const data = JSON.parse($input.first().json.data);

// Tag kun den første øvelse til test
//const testData = [data[0]];

return data.map(exercise => ({
  json: {
    id: exercise.id || exercise.name.replace(/[^a-zA-Z0-9]/g, '_'),
    name: exercise.name,
    force: exercise.force || 'unknown',
    level: exercise.level || 'unknown',
    mechanic: exercise.mechanic || 'unknown',
    equipment: exercise.equipment || 'unknown',
    category: exercise.category || 'unknown',
    primaryMuscles: exercise.primaryMuscles || [],
    secondaryMuscles: exercise.secondaryMuscles || []
  }
}));
